  1→use arcan_core::error::CoreError;
  2→use arcan_core::protocol::{ToolCall, ToolResult};
  3→use arcan_core::runtime::{Middleware, RunOutput, ToolContext};
  4→use lago_core::Journal;
  5→use lago_core::event::{EventEnvelope, EventPayload, MemoryScope};
  6→use lago_core::id::{BranchId, EventId, SessionId};
  7→use serde::{Deserialize, Serialize};
  8→use std::sync::{Arc, Mutex};
