 10→/// A structured learning entry captured from runtime events.
 11→#[derive(Debug, Clone, Serialize, Deserialize)]
 12→pub struct LearningEntry {
 13→    /// Category: "tool_failure", "user_correction", "run_error", "policy_denied"
 14→    pub category: String,
 15→    /// Human-readable description of what happened.
 16→    pub description: String,
 17→    /// The tool involved (if applicable).
 18→    pub tool_name: Option<String>,
 19→    /// The error message (if applicable).
 20→    pub error: Option<String>,
 21→    /// Session where this learning originated.
 22→    pub session_id: String,
 23→    /// Run where this learning originated.
 24→    pub run_id: String,
 25→}
 26→
 27→/// Buffer that accumulates learning entries during a run.
 28→#[derive(Debug, Default)]
 29→struct LearningBuffer {
 30→    entries: Vec<LearningEntry>,
 31→    run_id: String,
 32→    session_id: String,
 33→}
 34→
 35→/// Middleware that captures learning events from the agent runtime.
 36→///
 37→/// Records tool failures, middleware denials, and run errors as structured
 38→/// learning entries. At the end of each run, the accumulated learnings are
 39→/// persisted to the Lago journal as `Custom` events with type "learning_captured".
 40→pub struct LearningMiddleware {
 41→    journal: Arc<dyn Journal>,
 42→    buffer: Mutex<LearningBuffer>,
 43→}
 44→
 45→impl LearningMiddleware {
 46→    pub fn new(journal: Arc<dyn Journal>) -> Self {
 47→        Self {
 48→            journal,
 49→            buffer: Mutex::new(LearningBuffer::default()),
 50→        }
 51→    }
 52→
 53→    fn push_entry(&self, entry: LearningEntry) {
 54→        if let Ok(mut buf) = self.buffer.lock() {
 55→            buf.entries.push(entry);
 56→        }
 57→    }
 58→
 59→    /// Drain the buffer and build an envelope (if any entries exist).
 60→    fn drain_to_envelope(&self) -> Result<Option<EventEnvelope>, CoreError> {
 61→        let (entries, session_id, run_id) = {
 62→            let mut buf = self.buffer.lock().map_err(|e| {
 63→                CoreError::Middleware(format!("learning buffer lock poisoned: {e}"))
 64→            })?;
 65→            let entries = std::mem::take(&mut buf.entries);
 66→            let session_id = buf.session_id.clone();
 67→            let run_id = buf.run_id.clone();
 68→            (entries, session_id, run_id)
 69→        };
 70→
 71→        if entries.is_empty() {
 72→            return Ok(None);
 73→        }
 74→
 75→        Ok(Some(EventEnvelope {
 76→            event_id: EventId::default(),
 77→            session_id: SessionId::from_string(&session_id),
 78→            branch_id: BranchId::from("main"),
 79→            run_id: Some(lago_core::id::RunId::from_string(&run_id)),
 80→            seq: 0,
 81→            timestamp: 0,
 82→            parent_id: None,
 83→            payload: EventPayload::Custom {
 84→                event_type: "learning_captured".to_string(),
 85→                data: serde_json::json!({
 86→                    "scope": MemoryScope::Agent,
 87→                    "entry_count": entries.len(),
 88→                    "entries": entries,
 89→                }),
 90→            },
 91→            metadata: Default::default(),
 92→            schema_version: 1,
 93→        }))
 94→    }
 95→
 96→    fn flush_to_journal(&self) -> Result<(), CoreError> {
 97→        let Some(envelope) = self.drain_to_envelope()? else {
 98→            return Ok(());
 99→        };
100→
101→        // Use block_on since middleware runs in spawn_blocking context
102→        let journal = self.journal.clone();
103→        let handle = tokio::runtime::Handle::current();
104→        handle
105→            .block_on(async { journal.append(envelope).await })
106→            .map_err(|e| CoreError::Middleware(format!("failed to persist learnings: {e}")))?;
107→
108→        Ok(())
109→    }
110→}
111→
112→impl Middleware for LearningMiddleware {
113→    fn before_model_call(
114→        &self,
115→        request: &arcan_core::runtime::ProviderRequest,
116→    ) -> Result<(), CoreError> {
117→        // Initialize buffer with run context on first model call
118→        if let Ok(mut buf) = self.buffer.lock() {
119→            if buf.run_id.is_empty() {
120→                buf.run_id = request.run_id.clone();
121→                buf.session_id = request.session_id.clone();
122→            }
123→        }
124→        Ok(())
125→    }
126→
127→    fn pre_tool_call(&self, context: &ToolContext, call: &ToolCall) -> Result<(), CoreError> {
128→        // Set context if not set yet (e.g., first tool call in a run)
129→        if let Ok(mut buf) = self.buffer.lock() {
130→            if buf.run_id.is_empty() {
131→                buf.run_id = context.run_id.clone();
132→                buf.session_id = context.session_id.clone();
133→            }
134→        }
135→        // Nothing to capture before the call
136→        let _ = call;
137→        Ok(())
138→    }
139→
140→    fn post_tool_call(&self, context: &ToolContext, result: &ToolResult) -> Result<(), CoreError> {
141→        // Capture tool failures as learning entries
142→        if result.is_error {
143→            let error_text = result
144→                .output
145→                .get("error")
146→                .and_then(|v| v.as_str())
147→                .unwrap_or("unknown error")
148→                .to_string();
149→
150→            self.push_entry(LearningEntry {
151→                category: "tool_failure".to_string(),
152→                description: format!("Tool '{}' failed: {}", result.tool_name, error_text),
153→                tool_name: Some(result.tool_name.clone()),
154→                error: Some(error_text),
155→                session_id: context.session_id.clone(),
156→                run_id: context.run_id.clone(),
157→            });
158→        }
159→        Ok(())
160→    }
161→
162→    fn on_run_finished(&self, output: &RunOutput) -> Result<(), CoreError> {
163→        // Capture run errors
164→        if output.reason == arcan_core::protocol::RunStopReason::Error {
165→            self.push_entry(LearningEntry {
166→                category: "run_error".to_string(),
167→                description: "Run ended with error".to_string(),
168→                tool_name: None,
169→                error: None,
170→                session_id: output.session_id.clone(),
171→                run_id: output.run_id.clone(),
172→            });
173→        }
174→
175→        // Capture budget exceeded (agent may need different approach)
176→        if output.reason == arcan_core::protocol::RunStopReason::BudgetExceeded {
177→            self.push_entry(LearningEntry {
178→                category: "budget_exceeded".to_string(),
179→                description: "Run exhausted iteration budget without completing".to_string(),
180→                tool_name: None,
181→                error: None,
182→                session_id: output.session_id.clone(),
183→                run_id: output.run_id.clone(),
184→            });
185→        }
186→
187→        // Flush all accumulated learnings to journal
188→        self.flush_to_journal()
189→    }
190→}
