  1→use lago_core::error::LagoResult;
  2→use lago_core::event::{EventEnvelope, EventPayload, MemoryScope};
  3→use lago_core::projection::Projection;
  4→
  5→/// A single observation extracted from a runtime event.
  6→#[derive(Debug, Clone)]
  7→pub struct Observation {
  8→    /// Human-readable observation text.
  9→    pub text: String,
 10→    /// Sequence number of the source event.
 11→    pub source_seq: u64,
 12→    /// Timestamp of the source event (microseconds).
 13→    pub timestamp: u64,
 14→}
 15→
 16→/// Extracts observations from runtime events within a given scope.
 17→///
 18→/// The observer watches the event stream and accumulates observations
 19→/// until a compaction threshold is reached.
 20→pub struct Observer {
 21→    scope: MemoryScope,
 22→    observations: Vec<Observation>,
 23→    threshold: usize,
 24→}
 25→
 26→impl Observer {
 27→    pub fn new(scope: MemoryScope, threshold: usize) -> Self {
 28→        Self {
 29→            scope,
 30→            observations: Vec::new(),
 31→            threshold,
 32→        }
 33→    }
 34→
 35→    /// The scope this observer tracks.
 36→    pub fn scope(&self) -> MemoryScope {
 37→        self.scope
 38→    }
 39→
 40→    /// Current observation count.
 41→    pub fn count(&self) -> usize {
 42→        self.observations.len()
 43→    }
 44→
 45→    /// Whether the threshold has been reached.
 46→    pub fn threshold_reached(&self) -> bool {
 47→        self.observations.len() >= self.threshold
 48→    }
 49→
 50→    /// Drain all observations, resetting the observer.
 51→    pub fn drain(&mut self) -> Vec<Observation> {
 52→        std::mem::take(&mut self.observations)
 53→    }
 54→
 55→    /// Get observations as a slice.
 56→    pub fn observations(&self) -> &[Observation] {
 57→        &self.observations
 58→    }
 59→
 60→    /// Extract observation text from an event payload, if relevant.
 61→    fn extract_observation(payload: &EventPayload) -> Option<String> {
 62→        match payload {
 63→            EventPayload::Message {
 64→                role,
 65→                content,
 66→                model,
 67→                ..
 68→            } => {
 69→                let model_info = model
 70→                    .as_deref()
 71→                    .map(|m| format!(" [{m}]"))
 72→                    .unwrap_or_default();
 73→                Some(format!("{role}{model_info}: {content}"))
 74→            }
 75→            EventPayload::TextDelta { delta, .. } => Some(format!("assistant delta: {delta}")),
 76→            EventPayload::ToolCallCompleted {
 77→                tool_name, status, ..
 78→            } => Some(format!("tool:{tool_name} → {status:?}")),
 79→            EventPayload::StatePatched { patch, .. } => Some(format!("state patched: {patch}")),
 80→            EventPayload::ErrorRaised { message } => Some(format!("error: {message}")),
 81→            EventPayload::RunFinished {
 82→                reason,
 83→                total_iterations,
 84→                ..
 85→            } => Some(format!(
 86→                "run finished: {reason} ({total_iterations} iterations)"
 87→            )),
 88→            // Ignore lifecycle, sandbox, policy, branch, snapshot, and memory events
 89→            _ => None,
 90→        }
 91→    }
 92→}
 93→
 94→impl Projection for Observer {
 95→    fn on_event(&mut self, event: &EventEnvelope) -> LagoResult<()> {
 96→        if let Some(text) = Self::extract_observation(&event.payload) {
 97→            self.observations.push(Observation {
 98→                text,
 99→                source_seq: event.seq,
100→                timestamp: event.timestamp,
101→            });
102→        }
103→        Ok(())
104→    }
105→
106→    fn name(&self) -> &str {
107→        "arcan::observer"
108→    }
109→}
