111→/// Text-based compaction of observations.
112→///
113→/// In M1.2, this uses simple text concatenation with a summary header.
114→/// Future versions will use LLM-based summarization.
115→pub struct Reflector;
116→
117→impl Reflector {
118→    /// Compact observations into a summary string.
119→    pub fn compact(observations: &[Observation]) -> String {
120→        if observations.is_empty() {
121→            return String::new();
122→        }
123→
124→        let mut lines = Vec::with_capacity(observations.len() + 1);
125→        lines.push(format!(
126→            "Summary of {} observations (seq {}..{}):",
127→            observations.len(),
128→            observations.first().map(|o| o.source_seq).unwrap_or(0),
129→            observations.last().map(|o| o.source_seq).unwrap_or(0),
130→        ));
131→
132→        for obs in observations {
133→            lines.push(format!("- {}", obs.text));
134→        }
135→
136→        lines.join("\n")
137→    }
138→}
