  1→use lago_core::error::LagoResult;
  2→use lago_core::event::{EventEnvelope, EventPayload, MemoryScope};
  3→use lago_core::projection::Projection;
  4→use std::collections::{BTreeMap, HashSet};
  5→
  6→/// A committed memory entry tracked by the projection.
  7→#[derive(Debug, Clone)]
  8→pub struct CommittedMemory {
  9→    pub memory_id: String,
 10→    pub committed_ref: String,
 11→    pub supersedes: Option<String>,
 12→}
 13→
 14→/// Result of querying memory for a specific scope.
 15→#[derive(Debug, Clone)]
 16→pub struct MemoryQueryResult {
 17→    pub observations: Vec<String>,
 18→    pub reflection: Option<String>,
 19→    pub committed: Vec<CommittedMemory>,
 20→}
 21→
 22→/// Projection that builds queryable memory state from memory events.
 23→///
 24→/// Tracks observations, reflections, committed memories, and tombstones
 25→/// per scope. Tombstoned memory IDs are excluded from queries.
 26→pub struct MemoryProjection {
 27→    observations: BTreeMap<MemoryScope, Vec<String>>,
 28→    reflections: BTreeMap<MemoryScope, String>,
 29→    committed: BTreeMap<MemoryScope, Vec<CommittedMemory>>,
 30→    tombstoned: HashSet<String>,
 31→}
 32→
 33→impl MemoryProjection {
 34→    pub fn new() -> Self {
 35→        Self {
 36→            observations: BTreeMap::new(),
 37→            reflections: BTreeMap::new(),
 38→            committed: BTreeMap::new(),
 39→            tombstoned: HashSet::new(),
 40→        }
 41→    }
 42→
 43→    /// Query all memory for a given scope.
 44→    pub fn query(&self, scope: MemoryScope) -> MemoryQueryResult {
 45→        let observations = self.observations.get(&scope).cloned().unwrap_or_default();
 46→
 47→        let reflection = self.reflections.get(&scope).cloned();
 48→
 49→        let committed = self
 50→            .committed
 51→            .get(&scope)
 52→            .map(|entries| {
 53→                entries
 54→                    .iter()
 55→                    .filter(|e| !self.tombstoned.contains(&e.memory_id))
 56→                    .cloned()
 57→                    .collect()
 58→            })
 59→            .unwrap_or_default();
 60→
 61→        MemoryQueryResult {
 62→            observations,
 63→            reflection,
 64→            committed,
 65→        }
 66→    }
 67→
 68→    /// Get the latest reflection for a scope.
 69→    pub fn latest_reflection(&self, scope: MemoryScope) -> Option<&str> {
 70→        self.reflections.get(&scope).map(String::as_str)
 71→    }
 72→
 73→    /// Count observations for a scope.
 74→    pub fn observation_count(&self, scope: MemoryScope) -> usize {
 75→        self.observations.get(&scope).map(Vec::len).unwrap_or(0)
 76→    }
 77→}
 78→
 79→impl Default for MemoryProjection {
 80→    fn default() -> Self {
 81→        Self::new()
 82→    }
 83→}
 84→
 85→impl Projection for MemoryProjection {
 86→    fn on_event(&mut self, event: &EventEnvelope) -> LagoResult<()> {
 87→        match &event.payload {
 88→            EventPayload::ObservationAppended {
 89→                scope,
 90→                observation_ref,
 91→                ..
 92→            } => {
 93→                self.observations
 94→                    .entry(*scope)
 95→                    .or_default()
 96→                    .push(observation_ref.to_string());
 97→            }
 98→            EventPayload::ReflectionCompacted {
 99→                scope, summary_ref, ..
100→            } => {
101→                self.reflections.insert(*scope, summary_ref.to_string());
102→            }
103→            EventPayload::MemoryCommitted {
104→                scope,
105→                memory_id,
106→                committed_ref,
107→                supersedes,
108→            } => {
109→                // If this supersedes another memory, tombstone the old one
110→                if let Some(old_id) = supersedes {
111→                    self.tombstoned.insert(old_id.to_string());
112→                }
113→                self.committed
114→                    .entry(*scope)
115→                    .or_default()
116→                    .push(CommittedMemory {
117→                        memory_id: memory_id.to_string(),
118→                        committed_ref: committed_ref.to_string(),
119→                        supersedes: supersedes.as_ref().map(ToString::to_string),
120→                    });
121→            }
122→            EventPayload::MemoryTombstoned { memory_id, .. } => {
123→                self.tombstoned.insert(memory_id.to_string());
124→            }
125→            _ => {}
126→        }
127→        Ok(())
128→    }
129→
130→    fn name(&self) -> &str {
131→        "arcan::memory"
132→    }
133→}
