  1→use arcan_core::protocol::AgentEvent;
  2→use arcan_core::runtime::{ApprovalGateHook, ApprovalResolver};
  3→use lago_core::event::ApprovalDecision;
  4→use std::collections::HashMap;
  5→use std::sync::{Arc, Mutex};
  6→use std::time::Duration;
  7→use tokio::sync::oneshot;
  8→
  9→/// Outcome of an approval request.
 10→#[derive(Debug, Clone)]
 11→pub struct ApprovalOutcome {
 12→    pub decision: ApprovalDecision,
 13→    pub reason: Option<String>,
 14→}
 15→
 16→type EventHandler = Arc<dyn Fn(AgentEvent) + Send + Sync>;
 17→
 18→/// Gate that blocks tool execution pending human approval.
 19→///
 20→/// The middleware registers a pending approval via [`request_approval`], which
 21→/// returns a oneshot receiver. An HTTP handler (or timeout task) later calls
 22→/// [`resolve`] to unblock the middleware.
 23→pub struct ApprovalGate {
 24→    pending: Mutex<HashMap<String, oneshot::Sender<ApprovalOutcome>>>,
 25→    event_handler: Mutex<Option<EventHandler>>,
 26→    timeout: Duration,
 27→}
 28→
 29→impl ApprovalGate {
 30→    pub fn new(timeout: Duration) -> Self {
 31→        Self {
 32→            pending: Mutex::new(HashMap::new()),
 33→            event_handler: Mutex::new(None),
 34→            timeout,
 35→        }
 36→    }
 37→
 38→    /// Set the event handler used to emit approval events to SSE stream + journal.
 39→    /// Called by the AgentLoop before each run.
 40→    pub fn set_event_handler(&self, handler: EventHandler) {
 41→        let mut guard = self.event_handler.lock().unwrap();
 42→        *guard = Some(handler);
 43→    }
 44→
 45→    /// Clear the event handler after a run completes.
 46→    pub fn clear_event_handler(&self) {
 47→        let mut guard = self.event_handler.lock().unwrap();
 48→        *guard = None;
 49→    }
 50→
 51→    /// Emit an event through the handler if one is set.
 52→    pub fn emit_event(&self, event: AgentEvent) {
 53→        let guard = self.event_handler.lock().unwrap();
 54→        if let Some(handler) = guard.as_ref() {
 55→            handler(event);
 56→        }
 57→    }
 58→
 59→    /// Register a pending approval and return a receiver that will deliver the outcome.
 60→    ///
 61→    /// Spawns a timeout task that auto-denies after the configured duration.
 62→    /// Requires `Arc<Self>` so the timeout task can call [`resolve`].
 63→    pub fn request_approval(
 64→        self: &Arc<Self>,
 65→        approval_id: &str,
 66→    ) -> oneshot::Receiver<ApprovalOutcome> {
 67→        let (tx, rx) = oneshot::channel();
 68→        {
 69→            let mut pending = self.pending.lock().unwrap();
 70→            pending.insert(approval_id.to_string(), tx);
 71→        }
 72→
 73→        // Spawn timeout task
 74→        let gate = Arc::clone(self);
 75→        let aid = approval_id.to_string();
 76→        tokio::spawn(async move {
 77→            tokio::time::sleep(gate.timeout).await;
 78→            gate.resolve(
 79→                &aid,
 80→                ApprovalOutcome {
 81→                    decision: ApprovalDecision::Timeout,
 82→                    reason: None,
 83→                },
 84→            );
 85→        });
 86→
 87→        rx
 88→    }
 89→
 90→    /// Resolve a pending approval. Returns `true` if the approval was found and resolved.
 91→    pub fn resolve(&self, approval_id: &str, outcome: ApprovalOutcome) -> bool {
 92→        let tx = {
 93→            let mut pending = self.pending.lock().unwrap();
 94→            pending.remove(approval_id)
 95→        };
 96→        match tx {
 97→            Some(sender) => sender.send(outcome).is_ok(),
 98→            None => false,
 99→        }
100→    }
101→
102→    /// Return the IDs of all pending approvals.
103→    pub fn pending_ids(&self) -> Vec<String> {
104→        let pending = self.pending.lock().unwrap();
105→        pending.keys().cloned().collect()
106→    }
107→
108→    /// Return the number of pending approvals.
109→    pub fn pending_count(&self) -> usize {
110→        let pending = self.pending.lock().unwrap();
111→        pending.len()
112→    }
113→}
