116→    fn set_event_handler(&self, handler: Arc<dyn Fn(AgentEvent) + Send + Sync>) {
117→        ApprovalGate::set_event_handler(self, handler);
118→    }
119→
120→    fn clear_event_handler(&self) {
121→        ApprovalGate::clear_event_handler(self);
122→    }
123→}
