125→impl ApprovalResolver for ApprovalGate {
126→    fn resolve_approval(&self, approval_id: &str, decision: &str, reason: Option<String>) -> bool {
127→        let decision = match decision {
128→            "approved" => ApprovalDecision::Approved,
129→            "denied" => ApprovalDecision::Denied,
130→            _ => ApprovalDecision::Denied,
131→        };
132→        self.resolve(approval_id, ApprovalOutcome { decision, reason })
133→    }
134→
135→    fn pending_approval_ids(&self) -> Vec<String> {
136→        self.pending_ids()
137→    }
138→}
